// Normalize incoming JSON to uniform offers array
const raw = items[0].json;
const events = raw.events || [];
const normalized = events.flatMap(e => {
  const match = `${e.homeTeam} vs ${e.awayTeam}`;
  const bookmakers = e.canonical?.bookmakers || {};
  return Object.keys(bookmakers).flatMap(bk => {
    const odds = bookmakers[bk].odds || {};
    const oneXtwo = odds["1X2"] || odds["1x2"] || null;
    if (!oneXtwo) return [];
    const currency = bookmakers[bk].currency || "USD";
    return [{
      match,
      timestamp: e.timestamp,
      bookmaker: bk,
      market: "1X2",
      odds: { home: oneXtwo[0], draw: oneXtwo[1], away: oneXtwo[2] },
      url: bookmakers[bk].url || null,
      currency
    }];
  });
});
return normalized.map(r => ({ json: r }));

// Group offers by match
const arr = items.map(i => i.json);
const grouped = {};
arr.forEach(r => { if (!grouped[r.match]) grouped[r.match] = []; grouped[r.match].push(r); });
return Object.keys(grouped).map(m => ({ json: { match: m, offers: grouped[m] } }));

// Select best odds per outcome
const match = items[0].json;
const offers = match.offers;
const best = { home: null, draw: null, away: null };
offers.forEach(o => {
  const { bookmaker, odds, currency, url } = o;
  if (!best.home || odds.home > best.home.odds) best.home = { bookmaker, odds: odds.home, currency, url };
  if (!best.draw || odds.draw > best.draw.odds) best.draw = { bookmaker, odds: odds.draw, currency, url };
  if (!best.away || odds.away > best.away.odds) best.away = { bookmaker, odds: odds.away, currency, url };
});
return [{ json: { match: match.match, best } }];

// Surebet calculation and stakes
const { best } = items[0].json;
const cuotaHome = best.home.odds;
const cuotaDraw = best.draw.odds;
const cuotaAway = best.away.odds;
const margen = (1/cuotaHome) + (1/cuotaDraw) + (1/cuotaAway);
const surebet = margen < 1;
const beneficioPct = surebet ? (1 - margen) * 100 : 0;
const CAPITAL_TOTAL = 100; // parametrizar en variables de workflow
const denom = (1/cuotaHome) + (1/cuotaDraw) + (1/cuotaAway);
const stakeHome = (CAPITAL_TOTAL / cuotaHome) / denom;
const stakeDraw = (CAPITAL_TOTAL / cuotaDraw) / denom;
const stakeAway = (CAPITAL_TOTAL / cuotaAway) / denom;
return [{ json: { match: items[0].json.match, best, margen, surebet, beneficioPct, stakes: { home: stakeHome, draw: stakeDraw, away: stakeAway }, capitalTotal: CAPITAL_TOTAL } }];

// Value calculation using LLM probabilities
// LLM node returns text in items[0].json. Adapt if your LLM node returns differently.
let llmText = items[0].json.choices ? items[0].json.choices[0].message.content : items[0].json;
try { llmText = typeof llmText === 'string' ? llmText.trim() : JSON.stringify(llmText); } catch(e){}
let prob = { local:0.33, empate:0.33, visitante:0.34 };
try { const parsed = JSON.parse(llmText); if (parsed.local !== undefined) prob = { local: parsed.local, empate: parsed.empate, visitante: parsed.visitante }; } catch(e){}
const best = items[1].json.best || items[0].json.best;
const valHome = prob.local * best.home.odds;
const valDraw = prob.empate * best.draw.odds;
const valAway = prob.visitante * best.away.odds;
const valueBets = [];
if (valHome > 1.05) valueBets.push({ outcome: "home", valor: valHome, bookmaker: best.home.bookmaker, cuota: best.home.odds });
if (valDraw > 1.05) valueBets.push({ outcome: "draw", valor: valDraw, bookmaker: best.draw.bookmaker, cuota: best.draw.odds });
if (valAway > 1.05) valueBets.push({ outcome: "away", valor: valAway, bookmaker: best.away.bookmaker, cuota: best.away.odds });
return [{ json: { match: items[1].json.match || items[0].json.match, prob, valueBets, best: items[1].json.best, stakes: items[1].json.stakes, beneficioPct: items[1].json.beneficioPct } }];

// Convert & round stakes, avoid mixing currencies rule
const tipoCambio = 3.75; // parametrizar
function convert(amountUSD, currency) { if (currency === 'PEN') return Math.round(amountUSD * tipoCambio); return Math.round(amountUSD); }
function ajustar(monto) { let red = Math.round(monto / 5) * 5; const variacion = red * (Math.random() * 0.06 - 0.03); return Math.max(1, Math.round(red + variacion)); }
const source = items[0].json;
const stakes = source.stakes || { home:0, draw:0, away:0 };
const best = source.best;
const currencies = [best.home.currency, best.draw.currency, best.away.currency];
const mixedCurrencies = new Set(currencies).size > 1;
const sHome = ajustar(convert(stakes.home, best.home.currency));
const sDraw = ajustar(convert(stakes.draw, best.draw.currency));
const sAway = ajustar(convert(stakes.away, best.away.currency));
return [{ json: { match: source.match, mixedCurrencies, stakesRounded: { home: sHome, draw: sDraw, away: sAway }, currencies: { home: best.home.currency, draw: best.draw.currency, away: best.away.currency }, best, beneficioPct: source.beneficioPct || 0, valueBets: source.valueBets || [] } }];

